const Highlight = () => {
  const ref = useRef<HTMLDivElement>(null);
  const [text, setText] = useState(
    "Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id est laborum.",
  );
  const [searchText, setSearchText] = useState("dolor");

  useEffect(() => {
    if (!ref.current) return;
    return createPlainEditor({
      text: text,
      onChange: setText,
    }).input(ref.current);
  }, []);

  const reg = searchText ? new RegExp(`(${searchText})`) : null;

  return (
    <div>
      <div>
        <label htmlFor="search">search word</label>
        <input
          name="search"
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
        />
      </div>
      <div ref={ref} style={{ background: "white" }}>
        {text.split("\n").map((r, i) => (
          <div key={i}>
            {r ? (
              (reg ? r.split(reg) : [r]).map((t, j) =>
                t === searchText ? (
                  <mark key={j}>{t}</mark>
                ) : (
                  <span key={j}>{t}</span>
                ),
              )
            ) : (
              <br />
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

const Command = () => {
  const ref = useRef<HTMLDivElement>(null);
  const [text, setText] = useState("Hello world.\nこんにちは。\n👍❤️🧑‍🧑‍🧒");
  const editor = useMemo(
    () =>
      createPlainEditor({
        text: text,
        onChange: setText,
      }),
    [],
  );
  useEffect(() => {
    if (!ref.current) return;
    return editor.input(ref.current);
  }, []);

  const [insertText, setInsertText] = useState("text");

  return (
    <div>
      <div style={{ padding: 4 }}>
        <div>
          <input
            value={insertText}
            onChange={(e) => {
              setInsertText(e.target.value);
            }}
          />
          <button
            onClick={() => {
              editor.apply(InsertText, insertText);
            }}
          >
            insert
          </button>
        </div>
        <div>
          <button
            onClick={() => {
              editor.apply(Delete);
            }}
          >
            delete selection
          </button>
        </div>
        <div>
          <button
            onClick={() => {
              document.getSelection()?.modify("move", "forward", "character");
              ref.current?.focus();
            }}
          >
            move forward
          </button>
          <button
            onClick={() => {
              document
                .getSelection()
                ?.modify("move", "backward", "character");
              ref.current?.focus();
            }}
          >
            move backward
          </button>
          <button
            onClick={() => {
              document
                .getSelection()
                ?.modify("extend", "forward", "character");
              ref.current?.focus();
            }}
          >
            move focus forward
          </button>
          <button
            onClick={() => {
              document
                .getSelection()
                ?.modify("extend", "backward", "character");
              ref.current?.focus();
            }}
          >
            move focus backward
          </button>
        </div>
      </div>
      <div
        ref={ref}
        style={{
          backgroundColor: "white",
          border: "solid 1px darkgray",
          padding: 8,
        }}
      >
        {text.split("\n").map((r, i) => (
          <div key={i}>{r ? r : <br />}</div>
        ))}
      </div>
    </div>
  );
};

