};

const rebasePosition = (position: Position, op: Operation): Position => {
  switch (op.type) {
    case TYPE_DELETE: {
      const { start, end } = op;

      if (comparePosition(position, start) !== -1) {
        // start <= position
        return comparePosition(end, position) === -1
          ? // start <= end < position
            [
              movePath(
                position[0],
                normalizePath(start[0]) - normalizePath(end[0]),
