              ? getLineSize(lines[lineLength - 1]!) -
                (lineDiff === 0 ? 0 : at[1])
              : 0),
        ];
      }
      break;
    }
    case TYPE_SET_ATTR: {
      break;
    }
    default: {
      op satisfies never;
    }
  }
  return position;
};

const rebaseSelection = (
  selection: SelectionSnapshot,
  op: Operation,
): SelectionSnapshot => {
  return [rebasePosition(selection[0], op), rebasePosition(selection[1], op)];
};

/**
 * @internal
 */
export const isValidSelection = (
  doc: DocNode,
  [anchor, focus]: SelectionSnapshot,
): boolean => {
  return isValidPosition(doc, anchor) && isValidPosition(doc, focus);
};

/**
 * @internal
