export const applyOperation = <T extends DocNode>(
  doc: T,
  selection: SelectionSnapshot,
  op: Operation,
): [T, SelectionSnapshot] => {
  switch (op.type) {
    case TYPE_DELETE: {
      const { start, end } = op;
