export const filePaste = (
  handlerByMime: Record<string, (file: File) => InlineNode>,
): PasteExtension => {
  return (dataTransfer) => {
    for (const item of dataTransfer.items) {
      if (item.kind === "file") {
        const mapper = handlerByMime[item.type];
        if (mapper) {
          const file = item.getAsFile();
          if (file) {
            return [[mapper(file)]];
          }
        }
      }
    }
    return null;
  };
};


