const Combobox = () => {
  const ref = useRef<HTMLDivElement>(null);
  const [text, setText] = useState("");

  const [index, setIndex] = useState<number>(-1);
  const [focused, setFocused] = useState(false);

  const filtered = useMemo(
    () =>
      CHARACTERS.filter((c) =>
        c.toLowerCase().startsWith(text.toLowerCase()),
      ),
    [text],
  );

  const length = filtered.length;

  if (index > length - 1) {
    setIndex(-1);
  }

  const onPrev = useEffectEvent(() => {
    if (!length) return;
    setIndex((prev) => (prev === -1 ? length - 1 : prev - 1));
  });
  const onNext = useEffectEvent(() => {
    if (!length) return;
    setIndex((prev) => (prev >= length - 1 ? -1 : prev + 1));
  });
  const onComplete = useEffectEvent(() => {
    if (!length) return;
    if (index === -1) return;
    complete(index);
  });
  const onCancel = useEffectEvent(() => {
    if (!length) return;
    setIndex(-1);
  });

  const editor = useMemo(
    () =>
      createPlainEditor({
        text: text,
        singleline: true,
        keyboard: [
          hotkey("ArrowUp", onPrev),
          hotkey("ArrowDown", onNext),
          hotkey("Enter", onComplete),
          hotkey(" ", onComplete),
          hotkey("Escape", onCancel),
        ],
        onChange: setText,
      }),
    [],
  );

  const complete = (i: number) => {
    editor.apply(ReplaceAll, filtered[i]);
    setIndex(-1);
  };

  useEffect(() => {
    if (!ref.current) return;
    return editor.input(ref.current);
  }, []);

  const selected = length === 1 && filtered[0] === text;

  return (
    <div style={{ position: "relative", fontSize: "12px" }}>
      <div
        ref={ref}
        style={{
          height: COMBOBOX_INPUT_HEIGHT,
          width: COMBOBOX_INPUT_WIDTH,
          backgroundColor: selected ? "lightyellow" : "white",
          border: "solid 1px darkgray",
        }}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
      >
        {text ? text : <br />}
      </div>
      {focused && !!length && !selected && (
        <Menu index={index} items={filtered} onSelect={complete} />
      )}
    </div>
  );
};

