  if (!tokenizer) {
    return <div>{"Loading dictionaries"}</div>;
  }
  if (typeof tokenizer === "string") {
    return <div>Error: {tokenizer.toString()}</div>;
  }

  return (
    <div style={{ marginTop: 32 }}>
      <Editor tokenizer={tokenizer} />
    </div>
  );
};

