  /**
   * Functions to handle paste / drop events
   * @default [plainPaste()]
   */
  paste?: [PasteExtension, ...rest: PasteExtension[]];
  /**
   * TODO
   */
  isBlock?: (node: HTMLElement) => boolean;
  /**
   * Callback invoked when document changes.
