      const parserConfig: ParserConfig = {
        _document: document,
        _isBlock: isBlock as ParserConfig["_isBlock"],
        _isVoid: defaultIsVoidNode,
      };

      setContentEditable = () => {
        element.contentEditable = readonly ? "false" : "true";
        element.ariaReadOnly = readonly ? "true" : null;
