      // https://bugs.webkit.org/show_bug.cgi?id=165004
      const onKeyDown = (e: KeyboardEvent) => {
        if (isComposing) return;

        for (const handler of keydownHandlers) {
          if (handler(e)) {
            e.preventDefault();
            observer._record(false);
            return;
